import{_ as t,c as e,o as r,a3 as a}from"./chunks/framework.D5qxx6u8.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"visualization/plan.md","filePath":"visualization/plan.md","lastUpdated":1768466808000}'),o={name:"visualization/plan.md"},d=a('<p><strong>可视化工程师学习路线</strong>，分为 <strong>4 个阶段</strong>，每阶段包含学习目标、核心知识点、推荐资源（附链接）、实战项目建议和时间规划。</p><h2 id="🎯-总体目标" tabindex="-1">🎯 总体目标 <a class="header-anchor" href="#🎯-总体目标" aria-label="Permalink to &quot;🎯 总体目标&quot;">​</a></h2><blockquote><p>在 <strong>12 个月</strong> 内，掌握 WebGL 原理 + Three.js 实战 + 3D 可视化工程能力，具备应聘「WebGL 前端工程师」或「3D 可视化开发」岗位的能力。</p></blockquote><h2 id="🔰-阶段一-基础准备-第-1-2-月" tabindex="-1">🔰 阶段一：基础准备（第 1-2 月） <a class="header-anchor" href="#🔰-阶段一-基础准备-第-1-2-月" aria-label="Permalink to &quot;🔰 阶段一：基础准备（第 1-2 月）&quot;">​</a></h2><h3 id="✅-学习目标" tabindex="-1">✅ 学习目标 <a class="header-anchor" href="#✅-学习目标" aria-label="Permalink to &quot;✅ 学习目标&quot;">​</a></h3><ul><li>打牢前端与图形学基础</li><li>理解 3D 数学基本概念</li><li>能用 Canvas 2D 绘制简单动画</li></ul><h3 id="📚-核心内容" tabindex="-1">📚 核心内容 <a class="header-anchor" href="#📚-核心内容" aria-label="Permalink to &quot;📚 核心内容&quot;">​</a></h3><table><thead><tr><th>主题</th><th>学习要点</th><th>推荐资源</th></tr></thead><tbody><tr><td><strong>HTML5 Canvas 2D</strong></td><td><code>canvas</code> 元素、2D 上下文、路径绘制、动画循环（<code>requestAnimationFrame</code>）</td><td><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/Canvas_API/Tutorial" target="_blank" rel="noreferrer">MDN Canvas 教程</a></td></tr><tr><td><strong>JavaScript 进阶</strong></td><td>ES6+、TypedArray、模块化、异步编程</td><td><a href="https://zh.javascript.info/" target="_blank" rel="noreferrer">现代 JavaScript 教程（中文）</a></td></tr><tr><td><strong>线性代数基础</strong></td><td>向量、矩阵、点积/叉积、坐标变换（平移/旋转/缩放）</td><td><a href="https://www.bilibili.com/video/BV1ys411472E" target="_blank" rel="noreferrer">3Blue1Brown《线性代数的本质》</a>（B 站）<a href="https://www.khanacademy.org/math/linear-algebra" target="_blank" rel="noreferrer">可汗学院线性代数（英文）</a></td></tr><tr><td><strong>3D 图形基础概念</strong></td><td>坐标系（世界/相机/屏幕）、投影（透视/正交）、顶点、片段、光照模型</td><td>《3D 数学基础：图形与游戏开发》第 1–4 章（可选读）</td></tr></tbody></table><h3 id="💡-小项目实践" tabindex="-1">💡 小项目实践 <a class="header-anchor" href="#💡-小项目实践" aria-label="Permalink to &quot;💡 小项目实践&quot;">​</a></h3><ul><li>用 Canvas 实现一个会动的钟表</li><li>制作一个可拖拽的粒子系统（2D）</li></ul><h2 id="🔧-阶段二-webgl-原理入门-第-3-6-月" tabindex="-1">🔧 阶段二：WebGL 原理入门（第 3-6 月） <a class="header-anchor" href="#🔧-阶段二-webgl-原理入门-第-3-6-月" aria-label="Permalink to &quot;🔧 阶段二：WebGL 原理入门（第 3-6 月）&quot;">​</a></h2><blockquote><p>目标：<strong>理解 WebGL 渲染管线，能手写原生 WebGL 程序</strong></p></blockquote><h3 id="📚-核心内容-1" tabindex="-1">📚 核心内容 <a class="header-anchor" href="#📚-核心内容-1" aria-label="Permalink to &quot;📚 核心内容&quot;">​</a></h3><table><thead><tr><th>主题</th><th>关键知识点</th></tr></thead><tbody><tr><td>WebGL 上下文</td><td><code>getContext(&#39;webgl&#39;)</code>、检查支持</td></tr><tr><td>着色器（Shader）</td><td>GLSL 语法、顶点着色器 vs 片元着色器</td></tr><tr><td>缓冲区（Buffer）</td><td><code>ARRAY_BUFFER</code>、<code>ELEMENT_ARRAY_BUFFER</code></td></tr><tr><td>属性 &amp; Uniform</td><td>从 JS 传数据到 GPU</td></tr><tr><td>MVP 矩阵</td><td>模型（Model）、视图（View）、投影（Projection）矩阵</td></tr><tr><td>纹理映射</td><td>加载图片、绑定纹理、采样器</td></tr></tbody></table><h3 id="🔗-推荐资源-必学" tabindex="-1">🔗 推荐资源（必学） <a class="header-anchor" href="#🔗-推荐资源-必学" aria-label="Permalink to &quot;🔗 推荐资源（必学）&quot;">​</a></h3><ul><li>✅ <strong><a href="https://webglfundamentals.org/webgl/lessons/zh_cn/" target="_blank" rel="noreferrer">WebGL Fundamentals（中文版）</a></strong><br> 👉 最清晰、最系统的 WebGL 入门教程，从“画一个三角形”讲到高级技巧。</li><li><a href="https://developer.mozilla.org/zh-CN/docs/Web/API/WebGL_API/Tutorial" target="_blank" rel="noreferrer">MDN WebGL 教程</a></li><li>书籍：《<strong>WebGL 编程指南</strong>》（人民邮电出版社）——配套代码丰富</li></ul><h3 id="💡-实战项目" tabindex="-1">💡 实战项目 <a class="header-anchor" href="#💡-实战项目" aria-label="Permalink to &quot;💡 实战项目&quot;">​</a></h3><ol><li>绘制彩色三角形 → 旋转立方体</li><li>实现带纹理贴图的 3D 立方体</li><li>添加鼠标控制相机视角（使用 <code>mat4.lookAt</code>）</li></ol><blockquote><p>✨ 提示：不要跳过原生 WebGL！它是理解 Three.js 底层的关键。</p></blockquote><h2 id="🚀-阶段三-three-js-工程化开发-第-7-10-月" tabindex="-1">🚀 阶段三：Three.js 工程化开发（第 7-10 月） <a class="header-anchor" href="#🚀-阶段三-three-js-工程化开发-第-7-10-月" aria-label="Permalink to &quot;🚀 阶段三：Three.js 工程化开发（第 7-10 月）&quot;">​</a></h2><blockquote><p>目标：<strong>熟练使用 Three.js 快速构建 3D 可视化应用</strong></p></blockquote><h3 id="📚-核心内容-2" tabindex="-1">📚 核心内容 <a class="header-anchor" href="#📚-核心内容-2" aria-label="Permalink to &quot;📚 核心内容&quot;">​</a></h3><table><thead><tr><th>模块</th><th>学习重点</th></tr></thead><tbody><tr><td>场景（Scene）</td><td>对象树结构、Group 管理</td></tr><tr><td>相机（Camera）</td><td>PerspectiveCamera / OrthographicCamera</td></tr><tr><td>渲染器（Renderer）</td><td>WebGLRenderer、抗锯齿、阴影</td></tr><tr><td>几何体 &amp; 材质</td><td>BoxGeometry、MeshStandardMaterial、PBR</td></tr><tr><td>光照</td><td>DirectionalLight、PointLight、环境光</td></tr><tr><td>动画</td><td><code>Clock</code> + <code>requestAnimationFrame</code></td></tr><tr><td>交互</td><td>OrbitControls、Raycaster（射线拾取）</td></tr><tr><td>模型加载</td><td>GLTFLoader（推荐）、OBJLoader</td></tr><tr><td>后处理</td><td>EffectComposer、Bloom、SSAO</td></tr></tbody></table><h3 id="🔗-推荐资源" tabindex="-1">🔗 推荐资源 <a class="header-anchor" href="#🔗-推荐资源" aria-label="Permalink to &quot;🔗 推荐资源&quot;">​</a></h3><ul><li>✅ <strong><a href="https://threejs.org/docs/" target="_blank" rel="noreferrer">Three.js 官方文档（含示例）</a></strong></li><li>✅ <strong><a href="https://threejs-journey.com/" target="_blank" rel="noreferrer">Three.js Journey（付费但极推荐）</a></strong><br> 👉 Bruno Simon 的课程，项目驱动，涵盖 Shader、性能优化、3D 打包等</li><li>免费替代：<a href="https://www.bilibili.com/video/BV1ir4y1v7pH" target="_blank" rel="noreferrer">Three.js 中文教程（B 站 - 阿发你好）</a></li><li><a href="https://threejs.org/examples/" target="_blank" rel="noreferrer">Three.js Examples</a> —— 查阅官方 Demo 源码</li></ul><h3 id="💡-实战项目-1" tabindex="-1">💡 实战项目 <a class="header-anchor" href="#💡-实战项目-1" aria-label="Permalink to &quot;💡 实战项目&quot;">​</a></h3><ol><li>3D 地球仪（带国家标注 + 鼠标悬停）</li><li>产品 3D 展示页（支持旋转、缩放、切换材质）</li><li><strong>3D 数据可视化大屏</strong>：用柱状图/散点图在 3D 空间展示销售数据（结合 ECharts-GL 或自定义几何体）</li></ol><h2 id="🌐-阶段四-可视化专项-工程进阶-持续提升-第-11-12-月" tabindex="-1">🌐 阶段四：可视化专项 + 工程进阶（持续提升）（第 11-12 月） <a class="header-anchor" href="#🌐-阶段四-可视化专项-工程进阶-持续提升-第-11-12-月" aria-label="Permalink to &quot;🌐 阶段四：可视化专项 + 工程进阶（持续提升）（第 11-12 月）&quot;">​</a></h2><blockquote><p>目标：<strong>成为能落地企业级 3D 可视化项目的工程师</strong></p></blockquote><h3 id="📚-重点方向" tabindex="-1">📚 重点方向 <a class="header-anchor" href="#📚-重点方向" aria-label="Permalink to &quot;📚 重点方向&quot;">​</a></h3><table><thead><tr><th>方向</th><th>技术栈</th><th>学习建议</th></tr></thead><tbody><tr><td><strong>3D 数据可视化</strong></td><td>ECharts-GL、Three.js + D3、自定义着色器</td><td>学习如何将业务数据映射到 3D 空间（如热力图、关系网络）</td></tr><tr><td><strong>性能优化</strong></td><td>实例化渲染（Instancing）、LOD、Frustum Culling、Web Worker 分帧</td><td>阅读 <a href="https://threejs.org/manual/#zh/performance" target="_blank" rel="noreferrer">Three.js 性能指南</a></td></tr><tr><td><strong>Shader 进阶</strong></td><td>自定义材质、后处理、粒子系统</td><td>学习 <a href="https://thebookofshaders.com/01/?lan=ch" target="_blank" rel="noreferrer">The Book of Shaders（中文）</a></td></tr><tr><td><strong>数字孪生/智慧园区</strong></td><td>CesiumJS（地理空间）、3D Tiles、BIM 模型集成</td><td>了解 <a href="https://cesium.com/platform/cesiumjs/" target="_blank" rel="noreferrer">Cesium 官网</a></td></tr><tr><td><strong>工具链</strong></td><td>Vite + TypeScript + Webpack、GLTF 模型优化、CI/CD 部署</td><td>使用 <a href="https://github.com/vanruesc/vite-three-starter" target="_blank" rel="noreferrer">Three.js + Vite 模板</a></td></tr></tbody></table><h3 id="🔗-行业资源" tabindex="-1">🔗 行业资源 <a class="header-anchor" href="#🔗-行业资源" aria-label="Permalink to &quot;🔗 行业资源&quot;">​</a></h3><ul><li><strong>招聘要求参考</strong>：<a href="https://www.liepin.com/zhiwei/xxxxx" target="_blank" rel="noreferrer">WebGL 前端工程师招聘要求（猎聘）</a>（见知识库 [15]）</li><li><strong>开源项目学习</strong>： <ul><li><a href="https://github.com/mrdoob/three.js/tree/dev/examples" target="_blank" rel="noreferrer">Three.js 官方 Examples</a></li><li><a href="https://docs.pmnd.rs/react-three-fiber" target="_blank" rel="noreferrer">React Three Fiber（R3F）</a>（React 生态下的 Three.js 封装）</li></ul></li><li><strong>社区</strong>： <ul><li>CSDN / 掘金 搜索 “WebGL 可视化”</li><li>GitHub Trending: <code>topic:webgl</code></li></ul></li></ul><h3 id="💡-高阶项目-作品集必备" tabindex="-1">💡 高阶项目（作品集必备） <a class="header-anchor" href="#💡-高阶项目-作品集必备" aria-label="Permalink to &quot;💡 高阶项目（作品集必备）&quot;">​</a></h3><ol><li><strong>智慧城市 3D 大屏</strong>：集成楼宇、交通流、IoT 设备状态（可用假数据）</li><li><strong>WebGL + AI 可视化看板</strong>：如知识库 [1] 中提到的「3D 晋升看板」，用 ECharts-GL 渲染技能雷达</li><li><strong>3D 网络拓扑图</strong>：节点关系用 Three.js 粒子线连接，支持拖拽和搜索</li></ol><h2 id="📅-学习节奏建议-12-个月计划" tabindex="-1">📅 学习节奏建议（12 个月计划） <a class="header-anchor" href="#📅-学习节奏建议-12-个月计划" aria-label="Permalink to &quot;📅 学习节奏建议（12 个月计划）&quot;">​</a></h2><table><thead><tr><th>时间</th><th>重点</th></tr></thead><tbody><tr><td>第 1-2 月</td><td>基础准备（Canvas + 数学）</td></tr><tr><td>第 3–6 月</td><td>原生 WebGL（WebGL Fundamentals 全学完）</td></tr><tr><td>第 7–10 月</td><td>Three.js 核心 + 3 个项目</td></tr><tr><td>第 11-12 月</td><td>专项深化 + 作品集打磨 + 投简历</td></tr></tbody></table><h2 id="🎁-附加-学习工具推荐" tabindex="-1">🎁 附加：学习工具推荐 <a class="header-anchor" href="#🎁-附加-学习工具推荐" aria-label="Permalink to &quot;🎁 附加：学习工具推荐&quot;">​</a></h2><table><thead><tr><th>工具</th><th>用途</th><th>链接</th></tr></thead><tbody><tr><td><strong>ShaderToy</strong></td><td>在线写 GLSL、看别人炫酷 Shader</td><td><a href="https://www.shadertoy.com/" target="_blank" rel="noreferrer">https://www.shadertoy.com/</a></td></tr><tr><td><strong>Spector.js</strong></td><td>Chrome 插件，调试 WebGL 帧</td><td><a href="https://spector.babylonjs.com/" target="_blank" rel="noreferrer">https://spector.babylonjs.com/</a></td></tr><tr><td><strong>Blender</strong></td><td>免费建模软件，导出 GLTF</td><td><a href="https://www.blender.org/" target="_blank" rel="noreferrer">https://www.blender.org/</a></td></tr><tr><td><strong>Sketchfab</strong></td><td>免费下载 3D 模型（用于测试）</td><td><a href="https://sketchfab.com/" target="_blank" rel="noreferrer">https://sketchfab.com/</a></td></tr></tbody></table>',39),l=[d];function h(n,s,i,b,c,g){return r(),e("div",null,l)}const p=t(o,[["render",h]]);export{f as __pageData,p as default};
